var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"뭐야, 시시하게 다들 잔챙이들 밖에 없잖아?","JPN":"なーんだ、雑魚しかいないじゃん。つまんない。","ENG":"Oh come on, what a bore. They're just a bunch of grunts.","TWN":"什麼啊，只有這些弱不禁風的傢伙嗎？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_02"},{"id":"L4_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"이래서는 기껏 준비한 필살기도 못 쓰고 끝나겠는데?","JPN":"こんなんじゃせっかく用意した必殺技の出番もない気がするんだよね。","ENG":"I won't be able to show off my new special move at this rate.","TWN":"這樣一來，我就不能使用準備好的必殺技了啊？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"어이~!! 좀 더 근성을 보여주라고! 이 침식체 녀석들아!","JPN":"おーい！！　もっと根性見せろよ～！　侵食体ども！","ENG":"Hey! Show some grit, you stupid C.O.s!","TWN":"喂～！！再撐久一點啊！侵蝕體們！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L8_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"침식체가 저렇게 벌 떼 같이 달려드는데, 전혀 상대가 안 돼……!","JPN":"侵食体があんなに押し寄せてくるのに……まったく相手にならない……！","ENG":"The C.O.s are swarming her like crazy, but they're no match for her...!","TWN":"那麼多的侵蝕體一起的話，不可能打得過的……！"},"stage":{"bg":"HELI_NIGHT_2","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"칼 한번 휘둘렀다고 바다가 갈라지고 섬의 지형이 변화하고 있어…….","JPN":"刀を一振りしただけで海が割れて、島の地形が変わってる……","ENG":"With just one swing, the sea parts and the island's terrain is changing...","TWN":"一刀就劈開了大海，改變了島上的地形……？"},"stage":{"bg":"HELI_NIGHT_2","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L11_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"이렇게 멀리 있는데도 위력이 느껴질 정도야! 저게 한 사람으로부터 나오는 위력이 맞아?","JPN":"こんなに遠くにいるのに威力を肌で感じるぐらいだ。あれは本当に、人間一人が出せる威力なのか？","ENG":"Even when I'm this far away, I can still feel her power! Is this really all just from her?","TWN":"這麼遠的距離，我還能感受到殘餘的力量！這是人類能發揮出來的威力嗎？"},"stage":{"bg":"HELI_NIGHT_2","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"거의 살아있는 전략병기 수준이잖아……!?","JPN":"あれはもはや、歩く戦略兵器じゃないか……！？","ENG":"She's like a breathing strategic weapon at this point...!","TWN":"她就像一個活生生的戰略武器……？！"},"stage":{"bg":"HELI_NIGHT_2","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HELI_NIGHT_2","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"착각하지 마라, 신참.","JPN":"勘違いするな、新入り。","ENG":"Don't be mistaken, rookie.","TWN":"別搞錯了，新手。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L16_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"아무리 카운터라고 해도, 저 정도의 경지에 이르는 건 쉬운 일이 아니야.","JPN":"いくらカウンターとはいえ、誰でもあの境地に至れるわけではない。","ENG":"It's not easy for any Counter to reach her level.","TWN":"就算是制裁者，想要達到那種水準也不是件容易的事。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"하지만 네 눈으로 직접 보았듯이, 결코 불가능한 것도 아니지.","JPN":"だが、実際お前も見た通り、不可能なことでもない。","ENG":"But as you saw with your own eyes, it's not impossible.","TWN":"但正如你親眼所見，這並非不可能。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"저 녀석은 강해지겠다는 일념으로 한계의 한계를 뛰어넘어 저기까지 다다랐으니까.","JPN":"あいつは強くなりたいという一念で限界の限界を越え続け、あのレベルに至ったのだ。","ENG":"She has gone beyond her limits with the sole intention of becoming stronger.","TWN":"那傢伙憑藉自己想要變強的決心，超越極限，才能有今天的實力。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HELI_NIGHT_2","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"아직은 이렇게 멀리서 지켜보는 게 전부겠지만.","JPN":"今はこうして遠くから眺めるだけだが。","ENG":"Even if observing from afar is all you can do right now,","TWN":"雖然，現在的你只能遠遠地看著。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"관리국에 계속 있을 생각이라면, 저 녀석의 뒷모습을 마음 속에 새겨둬라.","JPN":"管理局に居続けるつもりなら、あいつの背中を忘れるな。","ENG":"if you're thinking of staying in the Administration, take the image of her back to the heart.","TWN":"但如果你打算繼續留在管理局，就好好記住那傢伙的背影吧。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"저 모습은 언젠가 네가 다다라야 할 모습이고, 또 누군가에게 보여주게 될 모습이니까.","JPN":"あれはいつかお前が辿り着かねばならない境地であり、また誰かに見せてやらねばならない姿なのだから。","ENG":"That is what you'll have to become and show to others one day.","TWN":"那將會是你總有一天會達到的樣子，也是別人會看到你的樣子。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"PILOT_VOICE_NULL_NULL","text":{"KOREA":"이수연 전대원님!","JPN":"カナミ・キズナ戦隊員！","ENG":"Ms. Lee Sooyeon!","TWN":"李秀妍戰隊員！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L31_1","type":"dialog","speaker":"PILOT_VOICE_NULL_NULL","text":{"KOREA":"아무래도 곧 CSE 레벨이 4단계에 다다라 4종 침식체가 출몰할 것 같습니다.","JPN":"もうすぐCSEレベルが4段階に達し、第4種侵食体が出現すると予想されます。","ENG":"The CSE Level will soon reach 4 and a Category 4 C.O. might appear soon.","TWN":"CSE等級很快就會達到4，很快就會出現4類侵蝕體了！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"흐응! 기다리고 있었다구!","JPN":"ふふん！　待ってたよ！","ENG":"Hmm! That's what I'm waiting for!","TWN":"唔！我正等著呢！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L34_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"이대로 필살기도 못 써보고 끝나면……!","JPN":"このまま必殺技も使えずに終わってしまったら……！","ENG":"I was getting worried that...!","TWN":"如果連必殺技都沒能使出來就結束的話……！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"찝찝해서 어떻게 하나 고민하던 참이었거든……!!","JPN":"後味悪そうだなって思ってたところなんでね……！！","ENG":"It'll all end without me being able to use my new special move...!!","TWN":"我會很苦惱的……！！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"필살기라고?","JPN":"必殺技だと？","ENG":"Special move?","TWN":"必殺技？"},"stage":{"bg":"HELI_NIGHT_2","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"그럼, 아직도 훨씬 강력한 공격이 남아 있다는 거야?","JPN":"まだまだ強い攻撃を繰り出せるってことなのか？","ENG":"She has an even more powerful attack that she hasn't used yet?","TWN":"她還沒有盡全力攻擊嗎？"},"stage":{"bg":"HELI_NIGHT_2","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"저 녀석, 설마 그걸……?","JPN":"あいつ、まさかあれを……？","ENG":"That idiot, she's not going to use that, is she...?","TWN":"那傢伙該不會要……？"},"stage":{"bg":"HELI_NIGHT_2","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L46_1","type":"dialog","speaker":"PILOT_VOICE_NULL_NULL","text":{"KOREA":"이수연 전대원님! 전방에 고밀도의 침식파 발생!","JPN":"カナミ・キズナ戦隊員！　前方に高密度の侵食波が発生しました！","ENG":"Ms. Lee Sooyeon! High-density Corruption ray detected ahead!","TWN":"李秀妍戰隊員！前方出現高密度侵蝕波！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L47_1","type":"dialog","speaker":"PILOT_VOICE_NULL_NULL","text":{"KOREA":"4종 침식체! 현실에 부상하였습니다!","JPN":"第4種侵食体！　現実に浮上しました！","ENG":"A Category 4 C.O. has emerged in the Normalside!","TWN":"是4類侵蝕體！它躍入現實了！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"그런 건 나도 알고 있다구!","JPN":"言われなくてもわかってるって！！","ENG":"I know that!","TWN":"你不說我也知道！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"간다! 이것이 바로 스승님과의 뜨거운 훈련으로 완성된 필! 살! 기!","JPN":"行くよ！　これこそ師匠との激しい訓練で完成した必・殺・技！","ENG":"Here I go! This is the special skill I perfected through intense training with Master!","TWN":"我上了！嚐嚐我跟著師父高強度訓練後，才領悟出的必！殺！技！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"멈춰, 이수연! 그 필살기는 아직……!","JPN":"待て、カナミ・キズナ！　その必殺技はまだ……！","ENG":"Stop, Sooyeon! That move is not–!","TWN":"住手，李秀妍！那個必殺技還是……！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L5_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"필──! 살──!","JPN":"必、殺─！","ENG":"Speciallll! Skilllll!","TWN":"必……！殺……！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"아토믹 힐데 퍼니시먼트으으으으으으으으으으으으───!","JPN":"アトミックヒルデパニッシュメントオオオオオオオ───！","ENG":"Atomic Hilde PUNISHMEEEEEENT!","TWN":"希爾德之……原子懲戒！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"보았느냐, 느꼈느냐. 이 어리석은 침식체 녀석아!","JPN":"見たか！　感じたか！　この愚かな侵食体め！","ENG":"See that? You foolish Corrupted Object.","TWN":"看到了嗎，感受到了嗎，你這個愚蠢的侵蝕體！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_02"},{"id":"L12_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"이것이 바로 관리국 S급 카운터! 이수연 님의 힘인 것이다!","JPN":"これぞ管理局S級カウンター、カナミ・キズナ様の力だ！","ENG":"You just got whooped by the Grade S Counter of the Administration! The one and only, Lee Sooyeon!","TWN":"這就是管理局的S級制裁者，李秀妍的力量！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"정말로 4종 침식체를…… 일격에 날려버렸어……!","JPN":"本当に第4種侵食体を……一撃で倒した……！","ENG":"She really defeated a Category 4 C.O.... in one blow...!","TWN":"真的一擊……就把4類侵蝕體打飛了……！"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"괴, 굉장하잖아……!?","JPN":"す、すごい……！","ENG":"Th-that's incredible...!","TWN":"難、難以置信……？！"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"헤헤! 어때요, 스승님?","JPN":"えへへ！　どうですか、師匠！","ENG":"Hehe! What do you think, Master?","TWN":"嘿嘿！怎麼樣，師父？"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"저, 또 한 번 스스로의 한계를 뛰어 넘은 필살기를 완성시켰다고요!","JPN":"私、また自分の限界を越えた必殺技を完成させました！","ENG":"I perfected a special skill that surpasses my limits again!","TWN":"我又一次完成了超越自身極限的必殺技！"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"이름하야, <color=#ffd34c>아토믹 힐데 퍼니시먼트</color>!!","JPN":"その名も<color=#ffd34c>アトミックヒルデパニッシュメント</color>！！","ENG":"I call it, <color=#ffd34c>Atomic Hilde Punishment</color>!!","TWN":"我將它命名為<color=#ffd34c>希爾德之原子懲戒</color>！！"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"스승님에 대한 존경심을 담아서 이름 지었어요, 잘했죠?","JPN":"師匠への尊敬の念を込めて名付けました！","ENG":"I named it out of respect for you, Master. I did a good job, right?","TWN":"這個名字代表著我對師父的敬重，我做的不錯吧？"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"……이수연.","JPN":"……カナミ・キズナ。","ENG":"...Sooyeon.","TWN":"……李秀妍。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_HATE"}}}},{"id":"L25_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"네? 왜 그러세요, 스승님?","JPN":"はい？　どうされました、師匠？","ENG":"Yes? What's wrong, Master?","TWN":"嗯？怎麼了，師父？"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_HATE"}}}},{"id":"L26_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"혹시 저의 새로운 필살기에 칭찬을…….","JPN":"私の新しい必殺技を褒め……","ENG":"Are you going to compliment me on my new special skill–","TWN":"你是要稱讚我的新必殺技……"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_HATE"}}}},{"id":"L29_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"당장 그 망할 기술명을 바꾸지 않으면, 관리국 완전무장으로 20Km를 뛰게 하겠다.","JPN":"今すぐその技名を変えないと、管理局の完全武装を背負い20kmを走らせるぞ。","ENG":"If you don't change that name immediately, I'm going to make you run 20\xA0km in full Administration combat gear.","TWN":"你再不趕緊改掉那個該死的名字，我就讓穿帶著管理局全副武裝跑20公里。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L30_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"네에에!? 너무해요! 스승님!!","JPN":"えええ！？　ひどいです、師匠！！","ENG":"WHAAAT?! That's so mean! Master!!","TWN":"欸……！？太過分了！師父！！"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"에휴…….","JPN":"はあ……","ENG":"Ugh...","TWN":"唉……"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"……그래서 작전 참관은 도움이 되셨나요, 앨리스 전대원님?","JPN":"……作戦の立ち会いは、役に立ちましたか？　アリスさん。","ENG":"...So, was your observation of our operation helpful, Ms. Braidwood?","TWN":"……所以，艾莉絲戰隊員，觀摩這次作戰對你有所幫助嗎？"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"수연이의 전투 스타일이 워낙 단순해서 참고되었을지는 잘 모르겠네요.","JPN":"キズナの戦闘スタイルって結構単純だから、あまり参考にならなかったかもしれませんが。","ENG":"I don't know if it was any help due to Sooyeon's fighting style being so simple.","TWN":"我不知道秀妍的戰鬥風格是否適合拿來用作參考。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"뭐라고? 이 멀대가!!","JPN":"何だとお、このヒョロガリ！！","ENG":"What did you just say? You, Beanstalk!!","TWN":"你說什麼？傻大個！！"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"아니, 덕분에 여러 가지를 알게 된 것 같아.","JPN":"いや、おかげで色々と気づかされた。","ENG":"Yes, I think I learned a lot today.","TWN":"不，我想多虧了她，我才學到了很多東西。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L39_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"카운터라는 게 얼마나 강력한 존재인지 그리고 내가 카운터로서 부족한 게 무엇인지.","JPN":"カウンターとはどれほど強力な存在なのか、そしてカウンターとして自分に何が足りてないのか。","ENG":"I learned how powerful Counters can be and what I lack as one.","TWN":"制裁者的威力有多大，而我作為制裁者又缺乏什麼。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"하하, 그거 다행이네요. 야크샤 부전대장님도 좋아하시겠는데요?","JPN":"はは、それはなによりです。ヤクシャー副戦隊長もきっと喜びますよ。","ENG":"Haha, that's good news. I think your Deputy Commander will be pleased with it.","TWN":"哈哈，那就好。夜叉副戰隊長應該會高興的吧？"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"고맙다, 왈가닥.","JPN":"ありがとう、お転婆。","ENG":"Thanks, tomboy.","TWN":"謝了，瘋丫頭。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"덕분에 카운터로서 중요한 걸 알게 됐어.","JPN":"おまえのおかげで、カウンターに何が必要なのか、大事なことがわかった気がする。","ENG":"Thanks to you, I learned something important as a Counter.","TWN":"謝謝你，讓我學到了作為制裁者重要的一點。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_LAUGH"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"어라? 중요한 거라고? 중요한 게 뭔데?","JPN":"え、何？　何が大事なの？","ENG":"Huh? Something important? What's that?","TWN":"什麼？重要的一點？什麼是重要的？"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L50_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"카운터로서 강해지기 위해 필요한 건, 스스로의 의식을 개변하는 것, 한계를 뛰어넘는 것.","JPN":"カウンターとして強くなるためには……自らの意識を改変すること、限界を超えることが必要だ。","ENG":"That for a Counter to become stronger, I must change my own consciousness and go beyond my limits.","TWN":"作為制裁者，想要變得更強，就需要改變自己的意識，超越自己的極限。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"그리고 마지막은…… 기합!","JPN":"そして最後は……気合！","ENG":"And lastly... spirit!","TWN":"以及……最後的最後！"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L2_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"멋있는 기술명을 외칠 필요가 있었던 거야!","JPN":"かっこいい技名を叫ぶ必要があったんだ！","ENG":"I also need to come up with cool skill names and shout them out!","TWN":"一個能夠大聲喊出來的帥氣的招式名字！"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"……어?","JPN":"……え？","ENG":"...Huh?","TWN":"……啊？"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"오오, 그걸 스스로 깨닫다니 대단한데!","JPN":"おお、それを自分で気づくとはやるじゃん！","ENG":"Ooh! It's amazing that you realized that all by yourself!","TWN":"噢噢，你竟然自己意識到了這一點，真了不起！"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L7_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"역시 아줌마, 뭘 아는 구나!","JPN":"さすがおばさん！　わかってるね！","ENG":"You clearly know what's up!","TWN":"不愧是阿姨，很懂嘛！"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"좋아! 돌아가서 같이 연습해 보자!","JPN":"よし、帰ったら一緒に練習するぞ！","ENG":"All right! We should go back and practice together!","TWN":"很好！我們回去一起練習吧！"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_PRIDE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"……하아.","JPN":"……はあ。","ENG":"...*Sigh*","TWN":"……哀。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"관리국에 바보가 하나 늘었군.","JPN":"管理局にバカがもう一人増えたか。","ENG":"That's one more idiot added to the Administration.","TWN":"管理局裡又多了一個笨蛋。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"필──! 살──!","JPN":"必、殺─！","ENG":"Speciallll! Skilllll!","TWN":"必……！殺……！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"애, 앨리스 익스플로저어어어어어어언……!","JPN":"あ、アリスエクスプロージョン……！","ENG":"A-Alice EXPLOOOOOSION...!!","TWN":"艾、艾莉絲爆裂……！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L21_1","type":"dialog","speaker":"LEESUYEON_ADMIN_SCHOOL_NULL","text":{"KOREA":"아이 참! 아줌마!","JPN":"もう、おばさんったら！","ENG":"Oh, come on!","TWN":"哎呀！阿姨！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_SCHOOL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LEESUYEON_ADMIN_SCHOOL_NULL","text":{"KOREA":"조금 더 자신감을 담아서 외쳐야지!","JPN":"もっと自信ありげに！　力強く叫ばないと！","ENG":"You gotta shout it out with more confidence!","TWN":"你要更自信一點！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_SCHOOL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LEESUYEON_ADMIN_SCHOOL_NULL","text":{"KOREA":"이수여어어어언──! 스트라이크으으으으──!","JPN":"カナミ・キズナァァァァ──！　ストラァァァァ──イクッ！","ENG":"Lee Sooyeoooooonnnnn! STRIIIIIKE!!!","TWN":"李秀妍……！絕殺……！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_SCHOOL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_SKILL_START"},{"id":"L25_1","type":"dialog","speaker":"LEESUYEON_ADMIN_SCHOOL_NULL","text":{"KOREA":"이렇게!","JPN":"こんなふうに！","ENG":"Like this!","TWN":"像這樣！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_SCHOOL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"그, 그래……?","JPN":"そ、そうか……","ENG":"Y-you think so...?","TWN":"是、是嗎？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"야, 이거 하면 할수록 얼굴이 화끈거리는데……. 진짜 이게 맞아?","JPN":"こ、これ……やればやるほど顔が火照ってくるんだが……本当にこれで合ってるか？","ENG":"But I feel so embarrassed the more I do this... Are you sure about this?","TWN":"可是越這樣做，就越感覺丟臉……這樣真的對嗎？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LEESUYEON_ADMIN_SCHOOL_NULL","text":{"KOREA":"어허! 내가 말했잖아, 아줌마!","JPN":"もうっ！　だから言ったでしょおばさん！","ENG":"Hey! How many times do I have to tell you!","TWN":"嗯呵！我告訴過你了，阿姨！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_SCHOOL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L31_1","type":"dialog","speaker":"LEESUYEON_ADMIN_SCHOOL_NULL","text":{"KOREA":"강해지기 위해서는 의심하면 안 된다니까? 스스로를 믿어야 한다구!","JPN":"強くなるためには疑いを捨てるの！　自分を信じるの！","ENG":"If you want to become stronger, you can't have any doubts! You have to believe in yourself!","TWN":"想要變強就不能有所懷疑，你必須相信自己！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_SCHOOL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"아, 알았어! 다시 해볼게!","JPN":"わ、わかった！　もう一度やってみる！","ENG":"O-okay! I'll try again!","TWN":"知、知道了！我再試試！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_SCHOOL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"킥킥, 역시 머리가 나쁘면 몸이 고생한다는 말이 딱 맞습니다요.","JPN":"きひひ、やっぱり頭が悪いと肉体が疲弊することになるでやんすね。","ENG":"Keke, guess the saying is true. When you're stubborn, you always do things the hard way.","TWN":"嘻嘻，頭腦簡單四肢發達，這句話說得沒錯。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"무슨 소리지르기 대회도 아니고, 저런다고 CRF가 강해질 리도 없는데 말입니다요.","JPN":"大声大会でもあるまいし、あんなことやってCRFが強くなるわけないでやんす。","ENG":"This isn't a shouting match. And what they're doing won't make their CRF any stronger either.","TWN":"又不是比嗓門，那樣練怎麼可能提高CRF嘛。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"덕분에 허접한 신참의 흑역사를 잔뜩 녹음했습니다요.","JPN":"まあおかげで新入りの黒歴史をたくさん保存できたでやんす。","ENG":"But thanks to that, I got lots of humiliating recordings of the noob.","TWN":"這下又讓我拍到了新人的黑歷史。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L39_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"후후, 그래도 뭔가 열심히 한다는 건 좋은 일이잖아?","JPN":"ふふ、でも何かに夢中になれるのって、いいことでしょう？","ENG":"Fu fuu, but it's a good thing that she's doing her best for something.","TWN":"呵呵，不過努力專注一件事也蠻好的不是嗎？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L40_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"당분간은 저대로 놔두자.","JPN":"しばらくそっとしておきましょう。","ENG":"Let's leave her be for a while.","TWN":"就先這樣放著別管吧。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L42_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"후후, 나름 구경하는 재미가 있기도 하고.","JPN":"ふふ……見てると楽しいしね。","ENG":"Fu fuu. Plus, it's fun watching them.","TWN":"呵呵，另外她們兩個還蠻有意思。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L46_1","type":"dialog","speaker":"LEESUYEON_ADMIN_SCHOOL_NULL","text":{"KOREA":"이수여어어어언──! 스트라이크으으으으──!","JPN":"カナミ・キズナァァァァ──！　ストラァァァァ──イクッ！","ENG":"Lee Sooyeoooooonnnnn! STRIIIIIKE!!!","TWN":"李秀妍……！絕殺……！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_SCHOOL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L47_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"애, 앨리스으으──! 익스플로저어어언──!","JPN":"あ、アリスゥゥゥ──！　エクスプロージョン──！","ENG":"A-Alicccceee! EXPLOOOOOSION!!!","TWN":"艾、艾莉絲……！爆裂……！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_SCHOOL_NULL","face":"UNIT_LAUGH"}}}}]`);export{e as default};